+    for (int i = 0; i < size(tSrS); ++i) {
+      int qo_idx = get<0>(tScS(i)) + q_tile_idx * CTA_Q;
+      int kv_idx = get<1>(tScS(i)) + (kv_tile_idx - 1) * CTA_KV;
