+template <typename DTypeO>
+float vec_cal_mse_(std::vector<DTypeO>& x, std::vector<DTypeO>& y) {
+  float mse = 0.0;
+  for (size_t i = 0; i < x.size(); ++i) {
+    float diff = float(x[i]) - float(y[i]);
+    mse += diff * diff;
+  }
+  return mse / x.size();
+}
+
+template <typename T>
+void vec_normal_(std::vector<T>& vec, float mean = 0.f, float std = 1.f, int seed = 327) {
+  std::mt19937 gen{seed};
+  // std::random_device rd{};
+  // std::mt19937 gen{rd()};
+
+  std::normal_distribution d{mean, std};
+  for (size_t i = 0; i < vec.size(); ++i) {
+    vec[i] = T(cutlass::float_e4m3_t(d(gen)));
+  }
+
+  if constexpr (sizeof(T) == 1) {
+    // view vec as uint8_t
+    uint8_t* data = reinterpret_cast<uint8_t*>(vec.data());
+    // random shuffle
+    std::shuffle(data, data + vec.size(), gen);
+  } else {
+    // random shuffle
+    std::shuffle(vec.begin(), vec.end(), gen);
+  }
+}
+
+template <typename T>
+void vec_uniform_(std::vector<T>& vec, float a = 0.f, float b = 1.f) {
+  std::random_device rd{};
+  std::mt19937 gen{rd()};
+  std::uniform_real_distribution d{a, b};
+  for (size_t i = 0; i < vec.size(); ++i) {
+    vec[i] = T(d(gen));
+  }
+}
+
+template <typename T>
+void vec_zero_(std::vector<T>& vec) {
+  std::fill(vec.begin(), vec.end(), T(0));
+}
+
+template <typename T>
+void vec_fill_(std::vector<T>& vec, T val) {
+  std::fill(vec.begin(), vec.end(), T(val));
+}
+
+template <typename T>
+void vec_randint_(std::vector<T>& vec, int low, int high) {
+  std::random_device rd{};
+  std::mt19937 gen{rd()};
+  std::uniform_int_distribution d{low, high};
+  for (size_t i = 0; i < vec.size(); ++i) {
+    vec[i] = T(d(gen));
+  }
+}
+
+template <typename T>
+void vec_randbin_(std::vector<T>& vec) {
+  std::random_device rd{};
+  std::mt19937 gen{rd()};
+  std::uniform_int_distribution d{0, 1024};
+  for (size_t i = 0; i < vec.size(); ++i) {
+    vec[i] = T(d(gen) % 2 ? -2 : 2);
+  }
+}
+
+template <typename T>
+size_t vec_bytes(const T& vec) {
+  return vec.size() * sizeof(typename T::value_type);
+}
+
+template <typename T>
+bool isclose(T a, T b, float rtol = 1e-5, float atol = 1e-8) {
+  return fabs(a - b) <= (atol + rtol * fabs(b));
+}
